        {
          "left": "Invalid Certificate Error",
          "right": "TCP/TLS connection"
        },
        {
          "left": "HTML downloads but the screen stays blank",
          "right": "Parsing and rendering"
        }
      ],
      "question": "Match each common browser symptom to the lifecycle stage where the failure likely occurs."
    },
